import { Link, useLocation } from 'react-router-dom';
import { useState, useEffect } from 'react';

export default function Header() {
  const location = useLocation();
  const [isScrolled, setIsScrolled] = useState(false);
  const [isMobileMenuOpen, setIsMobileMenuOpen] = useState(false);

  useEffect(() => {
    const handleScroll = () => {
      setIsScrolled(window.scrollY > 20);
    };
    window.addEventListener('scroll', handleScroll);
    return () => window.removeEventListener('scroll', handleScroll);
  }, []);

  const isHomePage = location.pathname === '/';

  return (
    <header className="bg-violet-600 text-white py-4 sticky top-0 z-50 shadow-lg">
      <div className="container mx-auto px-2">
        <div className="flex items-center justify-between">
          <div className="flex items-center space-x-4">
            <div className="w-12 h-12 bg-white/20 rounded-xl flex items-center justify-center">
              <i className="fas fa-bolt text-2xl"></i>
            </div>
            <div>
              <div className="hidden lg:block">
                <h1 className="text-lg font-semibold">Devis décennale Electricien</h1>
              </div>
              <div className="lg:hidden">
                <h1 className="text-sm font-semibold">Décennale</h1>
                <p className="text-xs text-violet-200">Electricien</p>
              </div>
            </div>
          </div>

          <a href="tel:0182834800" className="flex items-center space-x-3 bg-white/20 px-4 py-3 rounded-xl hover:bg-white/30 transition-colors">
            <i className="fas fa-phone text-xl"></i>
            <span className="text-xl font-bold">01 82 83 48 00</span>
          </a>
        </div>
      </div>
    </header>
  );
}
